from qiskit.visualization import plot_histogram
import matplotlib

before = {"00": 480, "11": 300, "01": 120, "10": 124}
after = {"00": 500, "11": 500, "01": 12, "10": 12}

def legend_texts(fig):
    leg = fig.axes[0].get_legend()
    return [t.get_text() for t in leg.get_texts()] if leg else []

calls = {
    "A": lambda: plot_histogram(before + after, legend=["before", "after"]),
    "B": lambda: plot_histogram(before, after, legend=["before", "after"]),
    "C": lambda: plot_histogram({"before": before, "after": after}),
    "D": lambda: plot_histogram([before, after], legend=["before", "after"]),
}
evidence = {}
proven = []
for k, fn in calls.items():
    try:
        fig = fn()
        is_fig = isinstance(fig, matplotlib.figure.Figure)
        leg = legend_texts(fig) if is_fig else []
        overlays = is_fig and set(leg) == {"before", "after"}
        evidence[k] = f"returned {type(fig).__name__}; legend={leg}; overlays both runs={overlays}"
        if overlays:
            proven.append(k)
    except Exception as e:
        evidence[k] = f"raised {type(e).__name__}: {str(e)[:90]}"

emit_verdict({
    "answer": proven,
    "evidence": evidence,
    "observed": {"overlay_calls": proven},
})
